Public class ETGRminCocoaUIBuilder extends SrsReportDataContractUIBuilder
{
    ETGRminCocoaContract             ETGRminCocoaContract;
    FormStringControl                       dimensionControl;

    DialogField                         fromDt,ToDt,VendId,Item,InvId;

}

Method.Source:
public void LookupVendId(FormStringControl _control)
{
    Query                   query = new Query();
    container               conVendId;
    QueryBuildDataSource    qbds;
    QueryBuildRange         qbr;

    qbds        = query.addDataSource(tableNum(VendTable));
    qbds.addSelectionField(fieldNum(VendTable,AccountNum));
    SysLookupMultiSelectGrid::lookup(query,_control,_control,_control,conVendId);
}

public void LookupItemId(FormStringControl _control)
{
    Query                   query = new Query();
    container               conItemId;
    QueryBuildDataSource    qbds;
    QueryBuildRange         qbr;

    qbds        = query.addDataSource(tableNum(InventTable));
    qbds.addSelectionField(fieldNum(InventTable,ItemId));
    SysLookupMultiSelectGrid::lookup(query,_control,_control,_control,conItemId);
}

public void LookupInvoiceId(FormStringControl _control)
{
    Query                   query = new Query();
    container               conInvId;
    QueryBuildDataSource    qbds;
    QueryBuildRange         qbr;

    qbds        = query.addDataSource(tableNum(VendPackingSlipJour));
    qbds.addSelectionField(fieldNum(VendPackingSlipJour,PackingSlipId));
    SysLookupMultiSelectGrid::lookup(query,_control,_control,_control,conInvId);
}

public void build()
{
    int i;
    ETGRminCocoaContract   contract;
    contract = this.dataContractObject() as ETGRminCocoaContract;
    fromDt = this.addDialogField(methodStr(ETGRminCocoaContract, parmfromdate),contract);
    ToDt = this.addDialogField(methodStr(ETGRminCocoaContract, parmtodate),contract);
    VendId = this.addDialogField(methodStr(ETGRminCocoaContract, parmVendAccount),contract);
    InvId = this.addDialogField(methodStr(ETGRminCocoaContract, parmInvoiceId),contract);
    Item = this.addDialogField(methodStr(ETGRminCocoaContract, parmItemId),contract);

}

public void postBuild()
{
    ETGRminCocoaContract   contract;
    super();
    contract = this.dataContractObject() as ETGRminCocoaContract;
    fromDt = this.bindInfo().getDialogField(contract,methodStr(ETGRminCocoaContract, parmfromdate));
    ToDt = this.bindInfo().getDialogField(contract,methodStr(ETGRminCocoaContract, parmtodate));
    VendId = this.bindInfo().getDialogField(contract,methodStr(ETGRminCocoaContract, parmVendAccount));

    VendId.registerOverrideMethod(methodStr(FormStringControl, lookup),
    methodStr(ETGRminCocoaUIBuilder, lookupVendId),this);
    if (VendId)
    {
        VendId.lookupButton(2);
    }
    item = this.bindInfo().getDialogField(contract,methodStr(ETGRminCocoaContract, parmItemId));
    item.fieldControl().mandatory(true);
    item.registerOverrideMethod(methodStr(FormStringControl, lookup),
    methodStr(ETGRminCocoaUIBuilder, lookupItemId),this);
    if (item)
    {
        item.lookupButton(2);
    }
    InvId = this.bindInfo().getDialogField(contract,methodStr(ETGRminCocoaContract, parmInvoiceId));

    InvId.registerOverrideMethod(methodStr(FormStringControl, lookup),
    methodStr(ETGRminCocoaUIBuilder, LookupInvoiceId),this);
    if (InvId)
    {
        InvId.lookupButton(2);
    }
}
